// Kotlin 登录测试代码
private fun testStudentLogin() {
    val testUsername = "student001"
    val testPassword = "123456"

    CloudApiHelper.login(testUsername, testPassword, object : CloudApiHelper.LoginCallback {
        override fun onResult(response: CloudApiHelper.LoginResponse) {
            if (response.success) {
                val userInfo = response.userInfo
                if (userInfo != null) {
                    println("登录成功: userId=\${userInfo.userId}, username=\${userInfo.username}")
                    println("用户角色: \${userInfo.role} (0=学生)")
                    println("班级ID: \${userInfo.classId}")

                    // 保存用户信息
                    UserManager.saveUserLogin(userInfo)

                    // 验证保存的信息
                    println("保存的用户ID: \${UserManager.getUserId()}")
                    println("登录状态: \${UserManager.isLoggedIn()}")
                    println("用户类型: \${UserManager.getUserTypeDescription()}")
                }
            } else {
                println("登录失败: \${response.message}")
            }
        }
    })
}
